%[text] ## Importing data
% Set up the Import Options and import the data %[task:5dc8]
opts = spreadsheetImportOptions("NumVariables", 12);

% Specify sheet and range
opts.Sheet = "Sheet1";
opts.DataRange = "A2:L243797";

% Specify column names and types
opts.VariableNames = ["Time", "state", "event_type", "damage_property", "damage_crops", "begin_lat", "begin_lon", "end_lat", "end_lon", "event_narrative", "storm_duration", "weathercats"];
opts.VariableTypes = ["datetime", "categorical", "categorical", "categorical", "categorical", "string", "string", "string", "string", "string", "categorical", "categorical"];

% Specify variable properties
opts = setvaropts(opts, ["begin_lat", "begin_lon", "end_lat", "end_lon", "event_narrative"], "WhitespaceRule", "preserve");
opts = setvaropts(opts, ["state", "event_type", "damage_property", "damage_crops", "begin_lat", "begin_lon", "end_lat", "end_lon", "event_narrative", "storm_duration", "weathercats"], "EmptyFieldRule", "auto");

% Import the data
weatherData = readtable("C:\Users\Filip\Documents\Praca\Inne materiały\MATLAB Expo 2025\MATLAB_Expo\MATLAB_LTC\weatherData.xlsx", opts, "UseExcel", false);

% Clear temporary variables
clear opts

% Display results
weatherData %[task:5dc8] %[output:2ff8c96c]
%%
% Define variable names for damage properties and crops
vars1 = ["damage_property", "damage_crops"];
for i = 1:length(vars1)
    vname = vars1(i);
    % Convert the weather data field to string format
    weatherData.(vname) = string(weatherData.(vname));
    % Identify entries containing "M" for million
    idxM = contains(weatherData.(vname),"M");
    % Remove "K" and "M" from the data
    weatherData.(vname) = erase(weatherData.(vname),["K","M"]);
    % Convert the cleaned data to double
    weatherData.(vname) = double(weatherData.(vname));
    % Scale entries that were originally in millions
    weatherData.(vname)(idxM) = weatherData.(vname)(idxM).*1e3;
end

% Define variable names for beginning longitude and latitude
vars2 = ["begin_lon", "begin_lat"];
for i = 1:length(vars2)
    vname = vars2(i);
    % Convert the weather data field to double format
    weatherData.(vname) = double(weatherData.(vname));
end

%%
% Add vars1 columns together to a new column called damage_total
weatherData.damage_total = sum(weatherData{:, vars1}, 2, 'omitnan');

% Replace damage_total with NaN if both damage_property and damage_crops are missing
missingIdx = ismissing(weatherData.damage_property) & ismissing(weatherData.damage_crops);
weatherData.damage_total(missingIdx) = NaN;
%%
% Remove missing data %[task:6e98]
[weatherData_cleaned,missingIndices] = rmmissing(weatherData);

% Display results
figure %[output:95e89610]
% Get locations of missing data
indicesForPlot = ismissing(weatherData.damage_total);
mask = missingIndices & ~indicesForPlot;

% Plot cleaned data
plot(find(~missingIndices),weatherData_cleaned.damage_total,SeriesIndex=1,LineWidth=1.5, ... %[output:95e89610]
    DisplayName="Cleaned data") %[output:95e89610]
hold on %[output:95e89610]

% Plot data in rows where other variables contain missing entries
plot(find(mask),weatherData.damage_total(mask),"x",SeriesIndex="none", ... %[output:95e89610]
    DisplayName="Removed by other variables") %[output:95e89610]

% Plot removed missing entries
x = repelem(find(indicesForPlot),3);
y = repmat([ylim(gca) missing]',nnz(indicesForPlot),1);
plot(x,y,"Color",[145 145 145]/255,DisplayName="Removed missing entries") %[output:95e89610]
title("Number of removed missing entries: " + nnz(indicesForPlot)) %[output:95e89610]

hold off %[output:95e89610]
legend %[output:95e89610]
ylabel("damage_total",Interpreter="none") %[output:95e89610]
clear indicesForPlot mask x y %[task:6e98]

%%
% Extract rows with the 50 largest values of damage_total
topDamageRows = weatherData_cleaned(...
    ismember(weatherData_cleaned.damage_total, ...
    maxk(weatherData_cleaned.damage_total, 50)), :);

%%
% Create geobubble of selected data %[task:6f54]
gb = geobubble(topDamageRows.begin_lat,topDamageRows.begin_lon,topDamageRows.damage_total); %[output:6a4a6cb1]

% Add title
title("topDamageRows.begin_lat vs. topDamageRows.begin_lon") %[task:6f54] %[output:6a4a6cb1]

